    { id: 93, text: "Professional ethics mandate that an engineer must uphold professional dignity and operate with what policy standard toward bribery, fraud, and corruption elements?", options: { a: "A professional penchant", b: "An operational predilection", c: "A flexible tolerance strategy", d: "A strict zero tolerance standard" }, answer: "d", tag: "Project Planning" },
    { id: 94, text: "The Nepal Engineers Association (NEA) was officially registered and established under the provisions of the:", options: { a: "Social Service Act", b: "Government of Nepal (GoN) Acts", c: "Public Association Act", d: "Nepal Engineering Council Act" }, answer: "a", tag: "Project Planning" },
    { id: 95, text: "In which year did the Government of Nepal formally enact the council legislation establishing the Nepal Engineering Council (NEC)?", options: { a: "2055 BS", b: "2056 BS", c: "2057 BS", d: "2058 BS" }, answer: "a", tag: "Project Planning" },
    { id: 96, text: "The Nepal Engineering Council (NEC) is structurally defined as a:", options: { a: "Statutory government and autonomous regulatory body", b: "Private sector commercial engineering group", c: "Voluntary non-profit professional club organization", d: "Standard line department under the Ministry" }, answer: "a", tag: "Project Planning" },
    { id: 97, text: "Which of the following functions does not fall under the statutory mandate and duties of the Nepal Engineering Council (NEC)?", options: { a: "Preparing and implementing engineering regulatory policies and plans", b: "Recognizing and accrediting academic engineering institutions", c: "Directly opening and operating engineering colleges commercially", d: "Prescribing basic minimum conditions for engineering student admissions" }, answer: "c", tag: "Project Planning" },
    { id: 98, text: "Which of the following operations is outside the scope of duties handled by the Nepal Engineering Council (NEC)?", options: { a: "Accreditation of engineering academic certificates", b: "Recognition of domestic and foreign engineering institutions", c: "Direct recruitment and appointment of college teachers", d: "All of the above" }, answer: "c", tag: "Project Planning" },
    { id: 99, text: "The professional code of conduct framework document officially issued by the NEC contains how many core articles?", options: { a: "8 articles", b: "6 articles", c: "7 articles", d: "11 articles" }, answer: "d", tag: "Project Planning" },
    { id: 100, text: "Who holds the statutory authority to officially appoint the Chairman of the Nepal Engineering Council?", options: { a: "The Government of Nepal (Cabinet)", b: "The President of Nepal", c: "The Ministry of Home Affairs", d: "The Supreme Court of Nepal" }, answer: "a", tag: "Project Planning" },
    { id: 101, text: "By statutory decree, an ex-officio seat on the Nepal Engineering Council (NEC) is reserved for the sitting President of:", options: { a: "Nepal Engineers Association (NEA)", b: "Society of Nepalese Architects (SONA)", c: "SCAEF Nepal", d: "National Planning Commission (NPC)" }, answer: "a", tag: "Project Planning" },
    { id: 102, text: "Who was officially appointed as the historic first President/Chairman of the Nepal Engineering Council?", options: { a: "Er. Shiw Mangal Giri", b: "Prof. Dr. Padma Bahadur Shahi", c: "Er. Ram Babu Sharma", d: "None of the above" }, answer: "c", tag: "Project Planning" },
    { id: 103, text: "What are the legal minimum requirements needed to qualify for appointment as the Chairman of the NEC?", options: { a: "Bachelor's degree in engineering + 10 years of experience", b: "Bachelor's degree in engineering + 15 years of experience", c: "Master's degree in engineering + 15 years of experience", d: "Master's degree in engineering + 10 years of experience" }, answer: "b", tag: "Project Planning" },
    { id: 104, text: "Who was appointed as the historic first Registrar of the Nepal Engineering Council?", options: { a: "Er. Bindeshwar Yadav", b: "Prof. Dr. Padma Bahadur Shahi", c: "Er. Shiw Mangal Giri", d: "Er. Hari Bahadur Darlami" }, answer: "a", tag: "Project Planning" },
    { id: 105, text: "The Vice-President/Vice-Chairman of the Nepal Engineering Council is officially:", options: { a: "Nominated directly by the Government of Nepal (GoN)", b: "Nominated internally by the NEC general committee", c: "Elected by general ballot among registered engineers", d: "Selected through open public competitive service testing" }, answer: "a", tag: "Project Planning" },
    { id: 106, text: "What is the baseline minimum professional qualification mandated for the Vice-Chairman position of the NEC?", options: { a: "Bachelor's degree with 15 years of professional engineering experience", b: "Bachelor's degree with 10 years of professional engineering experience", c: "Bachelor's degree with 5 years of professional engineering experience", d: "Possession of a basic engineering Bachelor's degree only" }, answer: "b", tag: "Project Planning" },
    { id: 107, text: "Which class of engineers are formally registered under Category A of the Nepal Engineering Council registry system?", options: { a: "General Registered Engineers", b: "Professional Engineers (PE)", c: "Registered Foreign Engineers", d: "All of the above" }, answer: "a", tag: "Project Planning" },
    { id: 108, text: "Non-Nepali Engineer definition according to NEC", options: { a: "non-Nepali engineer working under engineering institutions.", b: "Nepali engineer working abroad.", c: "freelancer engineer", d: "Nepali engineer working under engineering institutions" }, answer: "a", tag: "Project Planning" },
    { id: 109, text: "The total number of committee members nominated directly by the council internally to the core management team is:", options: { a: "2 members", b: "3 members", c: "5 members", d: "7 members" }, answer: "a", tag: "Project Planning" },
    { id: 110, text: "What is the statutory minimum number of female engineer members mandated to sit on the NEC executive board committee?", options: { a: "2", b: "3", c: "4", d: "5" }, answer: "c", tag: "Project Planning" },
    { id: 111, text: "In the structure of the Nepal Engineering Council, how many standing members are involved in the baseline examination committee?", options: { a: "5 members", b: "8 members", c: "9 members", d: "6 members" }, answer: "a", tag: "Project Planning" },
    { id: 112, text: "The cumulative number of professional engineers officially registered under the registry by the close of fiscal year 2078/12/31 is:", options: { a: "71", b: "61", c: "51", d: "41" }, answer: "b", tag: "Project Planning" },
    { id: 113, text: "What minimum score index percentage must an engineering college achieve on average during NEC inspection audits to secure institutional affiliation status?", options: { a: "50%", b: "60%", c: "70%", d: "80%" }, answer: "b", tag: "Project Planning" },
    { id: 114, text: "To sustain a temporary affiliation status, routine supervisory quality audits are conducted by the NEC at what frequency interval?", options: { a: "Two times per fiscal year", b: "Once every two years", c: "One time per fiscal year", d: "Three times per fiscal year" }, answer: "c", tag: "Project Planning" },
    { id: 115, text: "Which province of Nepal hosts the highest absolute number of institutional engineering colleges affiliated with the NEC?", options: { a: "Gandaki Province", b: "Bagmati Province", c: "Karnali Province", d: "Sudurpashchim Province" }, answer: "b", tag: "Project Planning" },
    { id: 116, text: "What is the statutory minimum qualification and service requirement needed to serve as the Registrar of the NEC?", options: { a: "Bachelor's degree in engineering + 10 years of professional experience", b: "Bachelor's degree in engineering + 15 years of professional experience", c: "Bachelor's degree in engineering + 20 years of professional experience", d: "Bachelor's degree in engineering + 7 years of professional experience" }, answer: "a", tag: "Project Planning" },
    { id: 117, text: "The historic first official amendment to the standing Nepal Engineering Council regulations was enacted in which year?", options: { a: "2057-03-08 BS", b: "2064-02-17 BS", c: "2069-03-15 BS", d: "2079-05-05 BS" }, answer: "b", tag: "Project Planning" },
    { id: 118, text: "If a practicing engineer violates sub-section 3(b) of the NEC Act 2055 by practicing without registration, the statutory fine amount is exactly:", options: { a: "NRs. 2,000 fine", b: "NRs. 3,000 fine", c: "NRs. 10,000 fine", d: "NRs. 25,000 fine" }, answer: "c", tag: "Project Planning" },
    { id: 119, text: "What is the maximum time window allocated by law for the formation of a fresh council following the dissolution of the sitting NEC board?", options: { a: "3 months", b: "6 months", c: "9 months", d: "1 year" }, answer: "a", tag: "Project Planning" },
    { id: 120, text: "Final structural approval to enact changes or updates to the rules and regulations of the Nepal Engineering Council is granted exclusively by:", options: { a: "The Government of Nepal (Cabinet)", b: "The NEC Executive Committee internally", c: "The Nepal Engineers Association (NEA)", d: "The Ministry of Education" }, answer: "a", tag: "Project Planning" },
    { id: 121, text: "As per the updated section 30(c) of the amended NEC Act (2079), general violations of council codes carry a maximum statutory fine of:", options: { a: "3,000", b: "5,000", c: "20,000", d: "25,000" }, answer: "d", tag: "Project Planning" },
    { id: 122, text: "Following the completion of the NEC annual general council meeting, the final review report must be officially submitted directly to:", options: { a: "The President of Nepal", b: "The Government of Nepal (GoN)", c: "The Ministry of Physical Infrastructure and Transport", d: "The Ministry of Home Affairs" }, answer: "b", tag: "Project Planning" },
    { id: 123, text: "In which year were the detailed sub-regulations governing Master's Program Affiliations formally approved and issued by the NEC?", options: { a: "2076-09-06 BS", b: "2077-05-26 BS", c: "2079-05-05 BS", d: "2080-04-12 BS" }, answer: "a", tag: "Project Planning" },
    { id: 124, text: "The official external independent financial auditor for the operations of the Nepal Engineering Council is appointed directly by:", options: { a: "The NEC Committee itself internally", b: "The Government of Nepal", c: "The Office of the Auditor General", d: "The Institute of Chartered Accountants of Nepal (ICAN)" }, answer: "a", tag: "Project Planning" },
    { id: 125, text: "During critical path method logic scheduling, when analyzing overlapping node convergences on a backward pass, which value rule is applied?", options: { a: "The maximum value is taken for forward passing calculations", b: "The minimum value is taken for backward passing calculations", c: "The early start baseline metric is locked in place", d: "The late finish metric is automatically set to zero" }, answer: "b", tag: "Project Planning" },
    { id: 126, text: "Which of the following definitions precisely characterizes the legal concept of a Copyright?", options: { a: "The right of the general public to freely duplicate published academic works", b: "Explicit commercial permission to reproduce any competitor's design ideas", c: "A legal protection framework that safeguards original works of authorship fixed in a tangible medium", d: "The unilateral capability to claim legal ownership over any public creative concept" }, answer: "c", tag: "Project Planning" },
    { id: 127, text: "What do hidden lines represent structurally inside an engineering layout drawing view?", options: { a: "Geometric features that are clearly visible from the current vantage point", b: "Standard extension line boundaries or leader callout coordinates", c: "Internal structural features that cannot be seen from the current external view", d: "The central axes of perfectly symmetrical structural parts" }, answer: "c", tag: "Project Planning" },
    { id: 128, text: "Which distinct stakeholder entity typically provides the prime financial funding resources needed to launch and execute a project?", options: { a: "Project Donor", b: "Project Sponsor", c: "Project Manager", d: "External Stakeholder" }, answer: "b", tag: "Project Planning" },
    { id: 129, text: "What is treated legally as the definitive, ultimate binding resolution mechanism for settling construction contract disputes after mediation fails?", options: { a: "Direct executive negotiation", b: "Neutral third-party mediation", c: "Contractual arbitration panel review", d: "Formal court litigation" }, answer: "d", tag: "Project Planning" },
    { id: 130, text: "In standard project evaluation interest notation tables, what does the functional parameter block indicator '[CRF (EP) - 8% - 7]' mean?", options: { a: "The annual discount capitalization rate is exactly 8%", b: "The capital resources are borrowed for a timeline duration of n = 7 years", c: "Both the 8% annual interest rate and the 7-year timeline duration match perfectly", d: "Neither of the factor parameter interpretations is correct" }, answer: "c", tag: "Project Planning" },
    { id: 131, text: "Contractual damages pre-calculated and explicitly written into a contract agreement to penalize a contractor for late delivery delays are termed:", options: { a: "Liquidated damages", b: "Unliquidated damages", c: "Direct out-of-pocket damages", d: "Tangible material damages" }, answer: "a", tag: "Project Planning" },
    { id: 132, text: "The legal definition of contract Liquidated Damages refers explicitly to a:", options: { a: "Financial penalty to repair physical wall and plaster defects from rain seepage", b: "Compensation cost to fix concrete dampness issues caused by pipe leaks", c: "Penalty cost billed to rectify sub-standard material quality components", d: "Pre-agreed financial compensation rate owed for delaying project completion beyond the locked contract date" }, answer: "d", tag: "Project Planning" },
    { id: 133, text: "Which specific project network presentation model plots scheduling tasks explicitly on the connecting arrows while tracking milestones at the junction nodes?", options: { a: "Activity-on-Node (AON) representation", b: "Activity-on-Arrow (AOA) representation", c: "Combined dual network representation models", d: "None of the above" }, answer: "b", tag: "Project Planning" },
    { id: 134, text: "Find the economical limit haul distance if the basic cost of borrow material excavation and hauling is Rs. 6 per m³ and the extra overhaul cost item is Rs. 0.04 per m³ per meter station.", options: { a: "100 m", b: "120 m", c: "150 m", d: "180 m" }, answer: "c", tag: "Project Planning" },
    { id: 135, text: "Which of the following items is outside the scope of items protected under standard copyright law frameworks?", options: { a: "Original artistic paintings, drawings, and photographs", b: "Composed musical scores and audio song tracks", c: "Produced cinematographic movies and video films", d: "General abstract design concepts and underlying article ideas that are mass-used" }, answer: "d", tag: "Project Planning" },
    { id: 136, text: "A semi-government public enterprise organization is properly characterized as:", options: { a: "An agency operating exclusively out of a fixed state-sanctioned grant budget", b: "An institute with free public employment options unchecked by rules", c: "An organization where board seats are filled entirely by its internal staff choice", d: "A corporate entity matching a blend of public management with partial state equity control and oversight" }, answer: "d", tag: "Project Planning" },
    { id: 137, text: "In international engineering procurement bidding workflows, what does the acronym 'RFP' stand for?", options: { a: "Request for Proposal", b: "Respect for Proposal", c: "Request for Purpose", d: "Respect for Purpose" }, answer: "a", tag: "Project Planning" },
    { id: 138, text: "Which manual drafting instrument is explicitly utilized for drawing precise circles or circular geometry arcs?", options: { a: "T-square ruler", b: "Drafting compass", c: "Protractor plate", d: "Set square combination" }, answer: "b", tag: "Project Planning" },
    { id: 139, text: "In project risk modeling statistics, the mathematical relationship defining the Standard Deviation is equal to:", options: { a: "(Variance)^(1/2)", b: "(Variance)²", c: "Variance / 6", d: "Variance" }, answer: "a", tag: "Project Planning" },
    { id: 140, text: "A clean, multi-radius geometric non-circular arch profile can be drawn manually on a layout board with the help of a:", options: { a: "French curve set", b: "Drafting compass", c: "Engineers scale", d: "Mechanical mini-drafter" }, answer: "b", tag: "Project Planning" },
    { id: 141, text: "What architectural feature dimension parameter does the symbol 'R' represent inside a mechanical drawing sheet?", options: { a: "Total outer diameter", b: "Fillet or arc radius", c: "Circumference boundary", d: "Cross-sectional area" }, answer: "b", tag: "Project Planning" },
    { id: 142, text: "Inside a Critical Path Method project schedule layout, the mathematical relationship between an activity's Total Float (TF) and Free Float (FF) is always:", options: { a: "TF >= FF", b: "TF < FF", c: "TF = FF strictly", d: "All of the above depending on path configurations" }, answer: "a", tag: "Project Planning" },
    { id: 143, text: "A French curve tool set is most effectively applied by a draftsman to draw:", options: { a: "Perfect constant-radius geometric circles", b: "Standard mathematical concentric ellipses", c: "Smooth, variable non-algebraic free-form curves", d: "Simple circular arc segments" }, answer: "c", tag: "Project Planning" },
    { id: 144, text: "The standard legal bid validity period duration mandated for public works tenders valued up to 100 million is exactly:", options: { a: "45 days", b: "60 days", c: "90 days", d: "105 days" }, answer: "c", tag: "Project Planning" },
    { id: 145, text: "Which of the following individual profiles is disqualified from holding an elected seat on the Nepal Engineering Council board registry?", options: { a: "A Nepali citizen practicing in the private sector", b: "A Nepali citizen employed in a public government department", c: "A Nepali citizen working under a private consulting corporation", d: "A foreign citizen engineer practicing domestic engineering works" }, answer: "d", tag: "Project Planning" },
    { id: 146, text: "Which of the following behavioral vectors represents an unprofessional quality for a certified engineer practicing in the field?", options: { a: "Maintaining professional and polite relationships with clients", b: "Upholding complete commercial honesty and transparency", c: "Demonstrating active bias toward political parties or groups during work allocations", d: "Maintaining strong up-to-date technical skills" }, answer: "c", tag: "Project Planning" },
    { id: 147, text: "An engineering drafting pencil graded in the 'B' hardness spectrum is standardly chosen to render:", options: { a: "Light, thin construction projection lines", b: "Dimension extension line paths", c: "Dark, clear visible object visual lines", d: "Continuous thin reference centerlines" }, answer: "c", tag: "Project Planning" },
    { id: 148, text: "If choosing alternative project option A completely blocks the possibility of selecting options B, C, or D, the group of alternatives is classified as:", options: { a: "Independent alternatives", b: "Dependent alternatives", c: "Mutually exclusive alternatives", d: "Contingent alternatives" }, answer: "c", tag: "Project Planning" },
    { id: 149, text: "According to statutory labor act guidelines, the maximum standard working hours permitted in a regular day is restricted to:", options: { a: "5 hours", b: "7 hours", c: "8 hours", d: "12 hours" }, answer: "c", tag: "Project Planning" },
    { id: 150, text: "In a PERT network event, the optimistic time (To) is 2 days, the pessimistic time (Tp) is 10 days, and the most likely time (Tm) is 3 days. Calculate the expected time (Te) output value.", options: { a: "3 days", b: "4 days", c: "5 days", d: "6 days" }, answer: "b", tag: "Project Planning" },
    { id: 151, text: "In municipal construction item rate analysis, the budgeting allocation for light tools and equipment machinery wear is calculated as:", options: { a: "1% of unskilled labor costs", b: "3% of unskilled labor costs", c: "5% of unskilled labor costs", d: "10% of unskilled labor costs" }, answer: "c", tag: "Project Planning" },
    { id: 152, text: "Dummy activities are introduced into a project scheduling network model explicitly to serve:", options: { a: "Grammatical ordering purposes", b: "Logical sequence dependency mapping purposes", c: "Both visual layout and logical tracking needs", d: "None of the above options" }, answer: "b", tag: "Project Planning" },
    { id: 153, text: "The structural locus geometric path traced by a point shifting uniformly along an oscillating pendulum arm from one tip to the other builds a:", options: { a: "Spiral curve profile", b: "Cycloid curve profile", c: "Involute curve profile", d: "Helix curve profile" }, answer: "a", tag: "Project Planning" },
    { id: 154, text: "In traditional indigenous Nepalese water mills (Ghatta layout), the raw material standardly shaped to build the rotating runner turbine blades is:", options: { a: "Carved hardwood logs", b: "Cast unreinforced concrete structural modules", c: "Chiseled heavy stone masonry elements", d: "Molded cast iron alloy units" }, answer: "a", tag: "Project Planning" },
    { id: 155, text: "What represents the main environmental hazard caused by widespread usage of toxic agricultural pesticides?", options: { a: "They directly cause physical wing deformations in freshwater fish species", b: "They directly kill beneficial backyard silkworms exclusively", c: "Mosquito vectors build rapid, permanent genetic immunity to DDT sprays", d: "Their chemical residues persist in water bodies and bioaccumulate through the ecosystem food chain" }, answer: "d", tag: "Project Planning" },
    { id: 156, text: "A structural steel truss system bridge configuration is engineering-wise preferred for clear span lengths matching which range?", options: { a: "Up to 32 meters maximum", b: "Between 10 to 30 meters short spans", c: "Between 30 to 375 meters medium-to-long ranges", d: "Extending exclusively beyond 200 meters long spans" }, answer: "c", tag: "Project Planning" },
    { id: 157, text: "The essential functional rooms that must be constructed during farm house residential layout design projects are:", options: { a: "Kitchen + bathroom + store room + farm utility space", b: "Kitchen + bathroom + office space", c: "Living room + utility space + greenhouse tracking zone", d: "Bedroom + dining room + walk-in pantry" }, answer: "a", tag: "Project Planning" },
    { id: 158, text: "How many mechanical suction cups are integrated into a standard commercial automated milking machine assembly tool to milk cows safely?", options: { a: "2 cups", b: "4 cups", c: "3 cups", d: "5 cups" }, answer: "b", tag: "Project Planning" }
